@contextmanager
def db():
    conn = sqlite3.connect(DB_PATH, timeout=15, check_same_thread=False)
    conn.row_factory = sqlite3.Row
    try:
        yield conn
        conn.commit()
    finally:
        conn.close()

def init_db():
    with db() as conn:
        conn.executescript("""
        CREATE TABLE IF NOT EXISTS inventory(
          id INTEGER PRIMARY KEY AUTOINCREMENT, category TEXT NOT NULL, subcategory TEXT NOT NULL,
          item_name TEXT NOT NULL, description TEXT DEFAULT '', quantity REAL NOT NULL DEFAULT 1,
          unit TEXT NOT NULL DEFAULT 'pieza(s)', brand TEXT DEFAULT '', condition_status TEXT DEFAULT 'Bueno',
          current_area TEXT DEFAULT '', expiration_date TEXT, lot_number TEXT DEFAULT '',
          estimated_unit_value REAL DEFAULT 0, destination TEXT NOT NULL DEFAULT 'Por definir',
          destination_detail TEXT DEFAULT '', transfer_status TEXT NOT NULL DEFAULT 'Pendiente',
          responsible_person TEXT DEFAULT '', transfer_date TEXT, notes TEXT DEFAULT '', photo BLOB,
          photo_name TEXT DEFAULT '', created_at TEXT NOT NULL, updated_at TEXT NOT NULL, created_by TEXT NOT NULL);
        CREATE TABLE IF NOT EXISTS audit_log(
          id INTEGER PRIMARY KEY AUTOINCREMENT, inventory_id INTEGER, action TEXT NOT NULL,
          detail TEXT DEFAULT '', user_name TEXT NOT NULL, created_at TEXT NOT NULL);
        """)

def h(v): return hashlib.sha256(str(v).encode()).hexdigest()
def authenticate(user,pin):
    u=user.strip().lower()
    if u==ADMIN_USER.lower() and h(pin)==h(ADMIN_PIN): return {"name":"Administrador","role":"admin"}
    if u == OWNER_USER.lower() and h(pin)==h(OWNER_PIN): return {"name":"Camelia Robles","role":"viewer"}

